sets = [set(s.split(',')) for s in df['courses']]
N = len(sets)
c = Counter()
for s in sets:
    if len(s) >= 2:
        for a,b in combinations(sorted(s), 2): c[frozenset({a,b})] += 1
for item, n in c.most_common(10):
    print(list(item), f'{n/N:.2%}')

sets = [set(s.split(',')) for s in df['courses']]
total = sum(1 for s in sets if TARGET in s)
co = Counter()
for s in sets:
    if TARGET in s:
        for c in s:
            if c != TARGET: co[c] += 1
res = sorted(co.items(), key=lambda x: x[1]/total, reverse=True)
for c, n in res[:3]:
    print(f'{TARGET} -> {c}: conf={n/total:.2%}')
